<template lang="en">
<div class="my-popups">
    <loader :is-visible="Loading"></loader>
     <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
         <div role="document" class="modal-dialog" style="max-width: 1200px !important;">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ $t('AssignBiller') }}</h4>
                    <!-- <span class="user-guide">
                        <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button" aria-expanded="false" aria-controls="collapseExample"> 
                            <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}
                        </a>
                        <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                            <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                <div class="con" v-html="$t('UgHiringAddDepartment')"></div>
                            </div>
                        </div>
                    </span> -->
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                
                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left pt-3">
                     <div class="col-lg-12 float-left ">
                        <dynamic-form lang="en" ref="AssignBiller" :schema="FormSchema"></dynamic-form>
                     </div>
                    <div class="col-lg-12 float-left " id="divContract">
                        <input id="hdnSelectedContractsEdit" type="hidden">
                        <div class="col-12 p-0 d-flex flex-wrap mb-2" id="divshowadddata">
                            <div class="col-12 p-0" id="divAvailableColumnsAll">
                                <div class="row m-0">
                                    <div class="heading-border mb-2">
                                        <h5 class="h5">
                                            <span>{{ $t("SelectedContracts") }}</span>
                                            <small class="float-right">
                                                <a href="javascript:;" data-toggle-tooltip="tooltip" data-original-title="Add Contracts" title="Add Contracts" @click="AddContract()">
                                                    <em class="fa fa-plus pr-2"></em>{{$t("AddContracts")}}
                                                </a> &nbsp;
                                                <a href="javascript:;" title="Delete" data-toggle-tooltip="tooltip" data-original-title="Delete Contracts" @click="Delete()">
                                                    <em class="fa fa-trash pr-1"></em>{{$t("Delete")}}
                                                </a>
                                            </small>
                                        </h5>
                                    </div>
                                    <div class="pt-2 d-inline-block w-100">
                                        <div class="col-12 p-0 mt-0">
                                            <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pr-1 pl-0">
                                                <input id="txtSelectedColumnsInSetup" maxlength="50" class="form-control" type="text" v-model="Searchtext" placeholder="Search by Contract Name." autocomplete="off">
                                            </div>
                                            <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pl-0">
                                                <div class="search-btm-btn background-0  form-check-inline">
                                                    <button title="Search"   @click="SearchButton(Searchtext)" class="btn btn-success mr-1 px-4"  data-original-title="Search">
                                                        <em class="fa fa-search"></em> Search
                                                    </button>
                                                    <button title="Clear" class="btn btn-danger px-4"  @click="Clear()" data-original-title="Clear">
                                                        <em class="fa fa-refresh"></em> Clear
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    <div class="col-md-12 p-0">
                                        <div class="listing mt-2">
                                            <div id="visiblecolumnSelected" class="table-responsive table-fix-header float-left">
                                                <table id="tblvisiblecolumn" class="table table-bordered mt-0" style="width:100%">
                                                   <thead class="thead-bg">
                                                        <tr>
                                                            <th class="text-center" style="width: 7%">
                                                                <input type="checkbox"
                                                                    :checked="allRowsSelected"
                                                                    :indeterminate.prop="someRowsSelected && !allRowsSelected"
                                                                    @change="toggleSelectAll"
                                                                    class="form-check-input position-static big-checkbox">
                                                            </th>

                                                            <th class="text-center" style="width:30%">
                                                                Contract Name
                                                            </th>

                                                            <th class="text-center" style="width:10%">
                                                                Flag<br>
                                                                <div class="form-group mb-0">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allFlag" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th  class="text-center" style="width:10%">
                                                                Invoice<br>
                                                                <div class="form-group mb-0 ">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allInvoice" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes ">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th class="text-center" style="width:10%">
                                                                Unprocess<br>
                                                                <div class="form-group mb-0 ">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allUnprocess" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes ">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th class="text-center" style="width:12%">
                                                                Billed /Unbilled<br>
                                                                <div class="form-group mb-0 ">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allBilledUnbilled" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes ">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th class="text-center" style="width:12%">
                                                                Rate Schedule<br>
                                                                <div class="form-group mb-0 ">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allRateSchedule" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes ">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th class="text-center" style="width:12%">
                                                                Billing Rule<br>
                                                                <div class="form-group mb-0 ">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allBillingRule" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes ">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th class="text-center" style="width:12%">
                                                                Report<br>
                                                                <div class="form-group mb-0">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allReport" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes ">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>
                                                        </tr>
                                                    </thead>

                                                    <tbody>
                                                        <tr <tr v-for="c in receivedData" :key="c.clientId">
                                                            <td>
                                                                <input type="checkbox" class="big-checkbox" v-model="c.selected">
                                                            </td>

                                                            <td style="width:30%">
                                                                <span   v-html="c.contractName + (c.BillerName ? ' - ' + c.BillerName : '')" :title="c.BillerName">
                                                                </span>
                                                            </td>                                                            
                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isFlag">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isInvoice">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isUnprocess">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isBilledUnbilled">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isRateSchedule">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isBillingRule">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isReport">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>                
                                                        </tr>

                                                        <tr v-if="receivedData.length === 0">
                                                            <td colspan="9" class="text-danger text-center">No record(s) found</td>
                                                        </tr>
                                                    </tbody>
                                                </table>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div class="clearfix"></div>
                                <div class="row flex-row-reverse mt-2">
                                    <div class="col-lg-6 text-right">
                                        <div class="search-btm-btn">
                                            <button id="" @click="Save()" class="btn btn-success" style="float:right;margin-left: 10px" title="" data-toggle-tooltip="tooltip"  data-original-title="Save">
                                                <i class="fa fa-save pr-2"></i><span>Save</span>
                                            </button>
                                            <button  @click="Close()" title="" id="" style="float:right;" class="btn btn-danger" data-toggle-tooltip="tooltip" data-original-title="Cancel">
                                                <em class="fa fa-close pr-2"></em>Cancel
                                            </button>
                                        </div>
                                    </div>
                                    <div class="col-lg-6">
                                        <div class="py-2">
                                            <span class="mandatory">Fields marked with an asterisk (*) are mandatory.</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <AvailableContract v-if="isAddContract" @submit-data="handleChildSubmit"></AvailableContract>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
import AvailableContract from '../Biller/AvailableContract.vue';

export default {
    components: {
        AvailableContract
    },
    props: {
        GroupBy: {
            type: String,
            required: false,
        },
        editPayload:{
            type:Object,
            required: false,
        },
        isEditJsonData: {
            type: Boolean,
            required: false
        },        
    },
    computed: {
        allRowsSelected() {
            if (this.receivedData.length === 0) return false;
            return this.receivedData.every(row => row.selected === true);
        },
        someRowsSelected() {
            return this.receivedData.some(row => row.selected === true);
        },

        allFlag: {            
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isFlag === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isFlag = value;
                });
            }
        },

        allInvoice: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isInvoice === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isInvoice = value;
                });
            }
        },

        allUnprocess: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isUnprocess === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isUnprocess = value;
                });
            }
        },

        allBilledUnbilled: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBilledUnbilled === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBilledUnbilled = value;
                });
            }
        },

        allRateSchedule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isRateSchedule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isRateSchedule = value;
                });
            }
        },

        allBillingRule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBillingRule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBillingRule = value;
                });
            }
        },

        allReport: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isReport === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isReport = value;
                });
            }
        }
    },
    watch: {
        editPayload: {
            immediate: true,
            handler(payload) {
                if (!payload) return;
                this.GetAssignBillerById(payload.AssignBiller[0]);                
            }
        }
    },
    data() {
        return {
            Loading: false,
            isShown: false,
            companyId: null,
            userId: null,
            isAddContract: false,
            ContractBillerListData: [],
            BillerListData: [],
            AssignBillerData: [],
            receivedData: [],
            receivedDataMaster: [],
            deletedItems: [],
            billerId:0,
            Searchtext:'',
            parentBillerid:'',
            ClientItemsList: [{
                clientId: 0,
                biller: '',
                isFlag: false,
                isInvoice: false,
                isUnprocess: false,
                isBilledUnbilled: false,
                isRateSchedule: false,
                isBillingRule: false,
                isReport: false
            }],
            AvailableContractData: [
                {
                    clientId: 0,
                    contractName: '',
                    checked: false,
                    isFlag: false,
                    isInvoice: false,
                    isUnprocess: false,
                    isBilledUnbilled: false,
                    isRateSchedule: false,
                    isBillingRule: false,
                    isReport: false
                }
            ],

            FormSchema: [{
                layoutType: "triple",
                Data: [
                     {
                            astype: "SearchableSelectField",
                            label: this.$t('Biller'),
                            name: "Biller",
                            value: "",
                            placeholder: "Select Biller",
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                actionButtons: { selectAll: true,  clear: true },
                                isMultiple: true,
                                itemFields: ['text'],
                                groupFields: [],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                 onChange: null
                            },                            
                            disabled: false,
                            validationRules: {"required": true},
                        },


                ]
            }]
        }
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  
            }, 50);
        });
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        await vm.GetBillerList();        
   },
    methods: {        
        toggleSelectAll(event) {
            const checked = event.target.checked;
            this.receivedData.forEach(row => {
                row.selected = checked;
            });
        },      

        GetBillerList: async function () {
            debugger;
            var vm = this;
            vm.Loading = true;
              try {
                    const url = `reqFrom=all&moduleName=Billing`;
                    const BillerResponse = (await DataService.GetBillerList(url));
                    const BillerResponses=JSON.parse(BillerResponse.data.result)
                    if (BillerResponses) {
                        // vm.$refs.AssignBiller.updateProperty("Biller", "config.options", BillerResponses);
                        // vm.$refs.AssignBiller.UpdateKeyValue();
                    
                        const BillerOptions = BillerResponses.map(item => ({
                            description:  null,
                            displayValue: item.USERNAME,
                            groupText: null,
                            groupValue: null,
                            metaData: item,
                            text: item.USERNAME,     
                            value: item.USERID       
                        }));

                        const billerField = vm.FormSchema[0].Data.find(f => f.name === 'Biller');
                        if (billerField) { billerField.config.options = BillerOptions;}
                        vm.$refs.AssignBiller?.UpdateKeyValue();
                        vm.Loading = false;
                    }
                } catch (error) {
                    console.error('Error loading Biller:', error);
                }
        },

        AddContract() {
            var vm = this;
            if(vm.isEditJsonData && vm.GroupBy=='Contract'){
                vm.ShowAlert("Select Grouping by Biller to Add Contract.", "warning", true);
                return;
            }else {
               vm.isAddContract = true;
            }            
        },
        GetAssignBillerById(item){
            debugger;
            var vm=this;
            if(vm.GroupBy=='Contract'){
                vm.parentBillerid= item.ClientIds;
            }            
            var biller=vm.GroupBy ? vm.GroupBy : 'Biller';
            var url = `groupId=${item.GroupId}&groupBy=${biller}`;
                DataService.GetAssignBillerById(url).then(response => {
                    debugger;
                if (response.status === 200 && response.data?.result) {
                    let resultData = response.data.result;
                    
                    if (typeof resultData === "string") {
                        resultData = JSON.parse(resultData);
                    }
                    // 🔥 push API result back into edit payload
                    vm.handleParentCall({
                        AssignBiller: resultData
                    });
                }
            });
        },

       Delete() {
            const vm = this;
            const selectedItems = vm.receivedData.filter(c => c.selected);

            if (!selectedItems.length) {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "warning", true);
                return;
            }

            vm.confirmR(vm.$t("ConfirmDelete"), true, vm.$t("Delete"), function () {
                if (!vm.deletedItems) vm.deletedItems = [];

                selectedItems.forEach(x => {
                    let contractId, billerId;
                    debugger
                    if (vm.GroupBy === "Biller") {
                        // Grouped by Biller: row = contract, biller comes from the selected biller field
                        contractId = x.clientId;
                        billerId = vm.FormSchema[0].Data[0].value;

                        // Handle if biller is multi-select (array)
                        if (Array.isArray(billerId)) {
                            billerId.forEach(bid => {
                                vm.deletedItems.push({
                                    clientId: Number(contractId),
                                    billerId: Number(bid)
                                });
                            });
                            return;
                        }
                    } else {
                        // Grouped by Contract: row shows biller assignment for a contract
                        // From your data pattern: clientId = biller, parentId = contract
                        contractId = x.parentId || x.contractId || x.clientId;  // contract ID (e.g. 505739)
                        billerId   = x.clientId || x.billerId;                   // biller ID (e.g. 533971)
                    }

                    if (!contractId || !billerId) {
                        console.warn("Cannot delete - missing IDs in row:", x);
                        return;
                    }

                    vm.deletedItems.push({
                        clientId: Number(contractId),
                        billerId: Number(billerId)
                    });
                });

                // Debug: see what will be sent
                console.log("Items queued for deletion:", JSON.stringify(vm.deletedItems, null, 2));

                // Remove from UI (optimistic update)
                vm.receivedData = vm.receivedData.filter(c => !c.selected);
            });
        },
      
      
       Save() {
            const vm = this;
            const hasDeletes = vm.deletedItems?.length > 0;
            const hasAdds   = vm.receivedData.length > 0;
            if (!hasDeletes && !hasAdds) {
                vm.ShowAlert(vm.$t("NoChangesToSave"), "warning", true);
                return;
            }
            // Require biller for add mode
            if (hasAdds && !vm.FormSchema?.[0]?.Data?.[0]?.value) {
                vm.ShowAlert("Please select Biller", "warning", true);
                return;
            }
            vm.Loading = true;
            const processDeletes = () => {
                if (!hasDeletes) return Promise.resolve();

                const deletePayload = {
                    ClientItemsList: vm.deletedItems.map(item => ({
                        clientId: item.clientId,      // contract
                        billerId: item.billerId,      // biller
                        isFlag: false,
                        isInvoice: false,
                        isUnprocess: false,
                        isBilledUnbilled: false,
                        isRateSchedule: false,
                        isBillingRule: false,
                        isReport: false
                    })),
                    BillerItemsList: [...new Set(vm.deletedItems.map(d => Number(d.billerId)))],
                    StatusId: 1003,
                    isEditJsonData: false,
                    groupBy: vm.GroupBy || "Biller"
                };
                console.log("DELETE PAYLOAD:", JSON.stringify(deletePayload, null, 2));

                return DataService.SaveAssignBiller(JSON.stringify(deletePayload))
                    .then(response => {
                        if (response.data?.status !== "Success" && response.data?.Status !== 1) {
                            throw new Error(response.data?.msg || "Delete failed");
                        }
                        return response;
                    });
            };

            const processAdds = () => {
                if (!hasAdds) return Promise.resolve();

                const addPayload = {
                    ClientItemsList: vm.receivedData.map(c => ({
                        clientId: c.clientId || c.parentId || c.contractId,
                        isFlag: !!c.isFlag,
                        isInvoice: !!c.isInvoice,
                        isUnprocess: !!c.isUnprocess,
                        isBilledUnbilled: !!c.isBilledUnbilled,
                        isRateSchedule: !!c.isRateSchedule,
                        isBillingRule: !!c.isBillingRule,
                        isReport: !!c.isReport
                    })),
                    BillerItemsList: Array.isArray(vm.FormSchema[0].Data[0].value)
                        ? vm.FormSchema[0].Data[0].value.map(Number)
                        : [Number(vm.FormSchema[0].Data[0].value)],
                    StatusId: 1001,
                    isEditJsonData: false,
                    groupBy: vm.GroupBy || "Biller"
                };

                console.log("ADD PAYLOAD:", JSON.stringify(addPayload, null, 2));

                return DataService.SaveAssignBiller(JSON.stringify(addPayload))
                    .then(response => {
                        if (response.data?.status !== "Success" && response.data?.Status !== 1) {
                            throw new Error(response.data?.msg || "Save failed");
                        }
                        return response;
                    });
            };

            // Execute sequentially: delete first → then add
            processDeletes()
                .then(() => processAdds())
                .then(() => {
                    vm.ShowAlert((hasDeletes && hasAdds)? vm.$t('UpdatedSuccessfully')
                            : hasDeletes ? vm.$t('DeletedSuccessfully', [vm.$t('Assignment')])
                                : vm.$t('AddedSuccess', [vm.$t('Biller')]),  "success",  true, vm.$t('Alert'));   
                                                   vm.$parent.GetBillerListing();
                    vm.Close();
                })
                .catch(err => {
                    console.error("Batch operation failed:", err);
                    vm.ShowAlert(err.message || "Operation failed (some changes may not have saved)", "danger", true);
                   
                })
                .finally(() => {
                    vm.Loading = false;
                    vm.deletedItems = []; // clear regardless
                });
        },

       SearchButton(txt) {
            if (!this.receivedDataMaster.length) {
                this.receivedDataMaster = [...this.receivedData];
            }
            const searchTxt = (txt || "").trim().toLowerCase();

            this.receivedData = this.receivedDataMaster.filter(c => c.contractName && c.contractName.toLowerCase().includes(searchTxt));
        },

        Clear() {
            this.receivedData = this.receivedDataMaster.slice();
            //this.receivedData = [...this.receivedDataMaster];
        },

        Close: function () {
            this.$parent.isAddBiller = false;
        }, 
        
        handleParentCall(payload) {
            debugger;
            const vm = this;

            if (!payload?.AssignBiller) return;

            const list = Array.isArray(payload.AssignBiller)
                ? payload.AssignBiller
                : [payload.AssignBiller];

            const parentRecords = list.map(c => ({
                clientId: c.CHILD_USER_ID || c.ClientIds,
                contractName: c.CHILD_NAME || c.GroupInfo || c.GroupName,
                selected: true,
                BillerName:c.BillerName||'',
                isFlag: Boolean(c.IsFlag),
                isInvoice: Boolean(c.IsInvoice),
                isUnprocess: Boolean(c.IsUnprocess),
                isBilledUnbilled: Boolean(c.IsBilledUnBilled ?? c.IsBilledUnbilled),
                isRateSchedule: Boolean(c.IsRateSchedule),
                isBillingRule: Boolean(c.IsBillingRule),
                isReport: Boolean(c.IsReport),

                parentId: c.PARENT_ID || c.GroupId,
                parentName: c.PARENT_NAME || c.GroupInfo
            }));

            // 🔥 SAFE MERGE
            vm.mergeReceivedData(parentRecords);

            vm.AvailableContractData = vm.receivedData;

            vm.billerId = vm.parentBillerid || list[0]?.GroupId;

            const normalizeArray = v => Array.isArray(v) ? v : v !== null && v !== undefined
                        ? v.toString().split(',').map(Number) : [];

            vm.FormSchema[0].Data[0].value = normalizeArray(vm.billerId);
            vm.FormSchema[0].Data[0].disabled = true;
        },

      handleChildSubmit(payload) {
            const vm = this;
            vm.Loading=true;

            if (!payload || !Array.isArray(payload.AssignBiller)) return;

            const childRecords = payload.AssignBiller.map(item => ({
                clientId: item.CHILD_USER_ID,
                contractName: item.CHILD_NAME,
                selected: item.isSelected ?? true,
                BillerName:item.BillerName||'',
                isFlag: true,
                isInvoice: true,
                isUnprocess: true,
                isBilledUnbilled: true,
                isRateSchedule: true,
                isBillingRule: true,
                isReport: true,

                parentId: item.PARENT_ID,
                parentName: item.PARENT_NAME
            }));

            // 🔥 SAFE MERGE
            vm.mergeReceivedData(childRecords);

            vm.AvailableContractData = vm.receivedData;
            vm.isAddContract = false;
            setTimeout(() => {
                vm.Loading=false;
            }, 200);
        },


       mergeReceivedData(newRecords) {
            if (!Array.isArray(this.receivedData)) {
                this.receivedData = [];
            }

            const map = new Map();
            // keep existing records
            this.receivedData.forEach(r => {
                const key = `${r.clientId}`;
                map.set(key, r);
            });

            // add only new records (no overwrite)
            newRecords.forEach(r => {
                const key = `${r.clientId}`;
                if (!map.has(key)) {
                    map.set(key, r);
                }
            });

            // reactive update
            this.receivedData = Array.from(map.values());
            this.receivedDataMaster = [...this.receivedData];
        },    

    },
}
</script>

